The `normalizeSQL` implementation has a few edge-case issues:
1. It doesn't handle backticks (`` ` ``), which are used for identifiers in Spanner. Whitespace inside backticked identifiers will be incorrectly collapsed.
2. It doesn't handle escaped quotes (e.g., `\'`) inside string literals. An escaped quote will prematurely terminate the `inString` state, leading to incorrect normalization of the rest of the string.
3. It doesn't handle the `''` escape sequence for single quotes in GoogleSQL correctly if it's used to represent a single quote character (though it accidentally works for collapsing whitespace because it just toggles the state twice).

```go
func normalizeSQL(sql string) string {
	var b strings.Builder
	inString := false
	var quote rune
	spacePending := false

	runes := []rune(strings.TrimSpace(sql))
	for i := 0; i < len(runes); i++ {
		r := runes[i]
		if inString {
			b.WriteRune(r)
			if r == '\\' && i+1 < len(runes) {
				i++
				b.WriteRune(runes[i])
			} else if r == quote {
				inString = false
			}
			continue
		}

		switch r {
		case '\'', '"', '`':
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			inString = true
			quote = r
			b.WriteRune(r)
		case ' ', '\t', '\n', '\r':
			spacePending = b.Len() > 0
		default:
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			b.WriteRune(r)
		}
	}

	return b.String()
}
