+	if !ok {
+		return false
+	}
+	toName, toSize, toMax, ok := sizedStringOrBytes(to)
+	if !ok || fromName != toName {
+		return false
+	}
+	if toMax {
+		return true
+	}
+	if fromMax {
+		return false
+	}
