// @exec: {"yield_time_ms": 1000, "max_output_tokens": 40000}
await tools.update_plan({
  explanation: "Context/spec/implementation artifacts are written; code anchors are identified. Inspecting exact test harness and generator error semantics before patching.",
  plan: [
    { step: "Ground task context: repo state, relevant memory, PR review comments, and existing autopilot state", status: "completed" },
    { step: "Create or update OMX context snapshot and autopilot spec/implementation artifacts", status: "completed" },
    { step: "Inspect affected code and tests before editing", status: "in_progress" },
    { step: "Implement review fixes with minimal, behavior-preserving diffs", status: "pending" },
    { step: "Run formatting, targeted tests, full Go test suite, and static checks where available", status: "pending" },
    { step: "Perform validation review for correctness, security, and maintainability", status: "pending" },
    { step: "Clean up autopilot state and report exact changes, evidence, risks, and quality scores", status: "pending" }
  ]
});
const cmd = `
set -euo pipefail
python3 - <<'PY'
from pathlib import Path
p=Path('.omx/state/sessions/omx-1777562909427-t3a338/autopilot-state.json')
p.parent.mkdir(parents=True, exist_ok=True)
p.write_text('''{
  "mode": "autopilot",
  "active": true,
  "current_phase": "execution",
  "state": {
    "context_snapshot_path": ".omx/context/fix-gemini-reviewed-points-pr9-20260430T153024Z.md",
    "spec_path": ".omx/plans/autopilot-spec.md",
    "implementation_plan_path": ".omx/plans/autopilot-impl.md"
  }
}
''')
PY
printf '%s\\n' '--- diff.go top/generator flow ---'
nl -ba diff/diff.go | sed -n '1,270p;700,760p'
printf '%s\\n' '--- diff tests sequences/options/unsupported/normalize/indexed recreate ---'
nl -ba diff/diff_test.go | sed -n '1080,1225p;1340,1395p;1440,1535p;1548,1625p;1748,1778p'
printf '%s\\n' '--- database tests top ---'
nl -ba diff/database_test.go | sed -n '1,120p'
`;
const out = await tools.shell_command({ command: cmd, workdir: "/Users/zchee/go/src/github.com/zchee/spanner-manager", timeout_ms: 120000 });
store("test_harness", out);
text(out);

